# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from web3 import Web3
from eth_account.messages import encode_defunct
from typing import Optional
import os

app = FastAPI(title="Web3 Authentication Service")

WEB3_PROVIDER_URI = os.getenv("WEB3_PROVIDER_URI", "http://localhost:8545")
w3 = Web3(Web3.HTTPProvider(WEB3_PROVIDER_URI))


class VerifySignatureRequest(BaseModel):
    address: str = Field(..., description="Expected Ethereum wallet address")
    message: str = Field(..., description="Original message that was signed")
    signature: str = Field(..., description="Hex-encoded signature")


class VerifySignatureResponse(BaseModel):
    authenticated: bool
    recovered_address: Optional[str] = None
    expected_address: Optional[str] = None
    message: str


def normalize_address(address: str) -> str:
    if not Web3.is_address(address):
        raise ValueError("Invalid Ethereum address")
    return Web3.to_checksum_address(address)


@app.get("/health")
def health():
    return {
        "status": "ok",
        "web3_connected": w3.is_connected(),
    }


@app.post("/auth/verify", response_model=VerifySignatureResponse)
def verify_signature(payload: VerifySignatureRequest):
    try:
        expected_address = normalize_address(payload.address)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    try:
        signable_message = encode_defunct(text=payload.message)
        recovered_address = w3.eth.account.recover_message(
            signable_message,
            signature=payload.signature,
        )
        recovered_address = Web3.to_checksum_address(recovered_address)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid message or signature")

    authenticated = recovered_address == expected_address

    return VerifySignatureResponse(
        authenticated=authenticated,
        recovered_address=recovered_address,
        expected_address=expected_address,
        message="Authentication successful" if authenticated else "Authentication failed",
    )


